channel.description:
Hi,

So far my frontity experience has been great with some struggles, but it takes some time to learn everything :) 

I am getting very frustrated because i am getting random 404 on some custom post type pages. 

All data is getting fetched on the archive pages, but sometimes I'm not able to click into the single review.

![Screenshot 2020-10-23 at 11.05.14|690x462](upload://cGc8fvPVKBygbe6iSYpyrOSvAmp.png) 
Here's a copy of my settings-file.

        const settings = {
      "name": "kreditdebit-frontity",
      "state": {
        "frontity": {
          "url": "https://kreditdebit.com",
          "title": "KreditDebit",
          "description": "Jämför lån för dina behov online"
        }
      },
     "packages": [
        {
          "name": "@frontity/google-analytics",
          "state": {
            "googleAnalytics": {
              "trackingId": "G-KTDBJQ3SQ3",
            },
          },
        },
      ],
      "packages": [
        {
          "name": "@awsmin/f1",
          "state": {
            "theme": {
              "menu": [
                [
                  "Start",
                  "/"
                ],
                [
                  "Privatlån",
                  "/privatlan"
                ],
                [
                  "Finansinsitut",
                  "/finansinsitut/"
                ],
                [
                  "Låna pengar",
                  "/lana-pengar/"
                ],
                [
                  "Om oss",
                  "/om-oss/"
                ]
              ],
              "featured": {
                "showOnList": true,
                "showOnPost": true
              }
            }
          }
        },
        {
          "name": "@frontity/wp-source",
          "state": {
            "source": {
              "api": "https://wp.kreditdebit.com/wp-json",
              "homepage": "/homepage",
              "postsPage": "/artiklar",
              postTypes: [
                {
                  type: "prp_reviews", // type slug
                  endpoint: "prp_reviews", // REST API endpoint
                  archive: "/finansinsitut" // link where this custom posts are listed
                }
              ]
            }
          }
        },
        "@frontity/tiny-router",
        "@frontity/html2react",
        "@frontity/yoast",
        "frontity-contact-form-7"        
        ]   
    };

    export default settings;
